INSERT INTO pages (slug, title, content_json, created_by_id, created_by_name, public, version, owner_type)
VALUES
  ('agm', 'Annual General Meeting (AGM)', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This procedure covers how the AGM is planned, run, and recorded. The AGM is the Society''s primary democratic event and must be conducted properly.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Legal requirements","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Under the Incorporated Societies Act 2022, the Society must hold an AGM within six months of the end of each financial year. The AGM must:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Receive the annual financial statements","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Receive the Custodian Board''s report on the year","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Conduct sortition to select the incoming Custodian Board","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Appoint officers for the coming year (Secretary, Treasurer, Contact Persons)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Transact any other business of which proper notice has been given","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Timeline","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"8 weeks before — Set the date and book a venue (physical or online)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"6 weeks before — Publish notice of the AGM to all Voting Members","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"4 weeks before — Publish the agenda, financial statements, and Board report","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"30 days before — Open nominations for Custodian Board sortition pool","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"7 days before — Close nominations; confirm sortition pool","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"AGM day — Run the meeting per the agenda below","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":6,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"14 days after — Publish minutes to all members","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":7,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Running the meeting","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Open the meeting and confirm quorum (at least the number of Voting Members required by the constitution for a valid AGM).","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Confirm the agenda.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Receive and note the financial statements.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Receive and note the Board''s annual report.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Conduct sortition — draw five names from the confirmed pool of nominees.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Appoint officers for the coming year.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":6,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Transact any other notified business.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":7,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Close the meeting.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":8,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Sortition procedure","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The nominations list is read aloud and confirmed.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Names are written on identical slips of paper (or a verified digital equivalent) and mixed thoroughly.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A member who is not a nominee draws five names.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Each drawn name is read aloud and confirmed as willing and available to serve.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If a drawn person is unavailable, draw again until five confirmed members are selected.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Minutes","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Minutes must record: who attended, the financial statements received, the results of sortition (names of incoming Board), officers appointed, and any resolutions passed.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Minutes are published to all members within 14 days and retained permanently.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-proc-agm'),
  ('board-meeting', 'Custodian Board Meeting', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This procedure covers how a standard Custodian Board meeting is prepared for and run.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Before the meeting","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Set the date","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" — at least five working days before the meeting, confirm the date, time, and location (in person or video call) with all five members.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Draft the agenda","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" — the facilitator (or the member who called the meeting) drafts the agenda and circulates it at least two days before the meeting. A standard agenda includes:","type":"text","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Conflicts of interest — any member declares interests relevant to agenda items","type":"text","version":1}],"direction":"ltr","format":"","indent":1,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Minutes of the previous meeting — confirmed as accurate","type":"text","version":1}],"direction":"ltr","format":"","indent":1,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Matters arising from previous minutes","type":"text","version":1}],"direction":"ltr","format":"","indent":1,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Financial report (at quarterly meetings)","type":"text","version":1}],"direction":"ltr","format":"","indent":1,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Substantive items for decision","type":"text","version":1}],"direction":"ltr","format":"","indent":1,"type":"listitem","value":5,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Complaints or formal matters (if any)","type":"text","version":1}],"direction":"ltr","format":"","indent":1,"type":"listitem","value":6,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Correspondence","type":"text","version":1}],"direction":"ltr","format":"","indent":1,"type":"listitem","value":7,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Other business","type":"text","version":1}],"direction":"ltr","format":"","indent":1,"type":"listitem","value":8,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Date of next meeting","type":"text","version":1}],"direction":"ltr","format":"","indent":1,"type":"listitem","value":9,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Prepare papers","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" — any documents members need to read before the meeting are circulated with the agenda.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Running the meeting","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Open the meeting and confirm all five members are present.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Appoint a facilitator by consensus.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Ask whether any member has a conflict of interest on any agenda item; record any declarations.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Work through the agenda. The facilitator ensures each member has the opportunity to speak on each item.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"For each decision item, confirm consensus explicitly: \"Are we all agreed?\" Record the decision.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Agree action items: for each, record what is to be done, who is responsible, and by when.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":6,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Close the meeting and confirm the date of the next meeting.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":7,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"After the meeting","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The facilitator (or an assigned member) writes up the minutes within 48 hours of the meeting.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Minutes are circulated to all Board members for review.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Minutes are published to all Voting Members within 14 days.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Action items are followed up by the responsible persons.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-proc-board-meeting'),
  ('backup-and-recovery', 'Backup and Recovery', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This procedure covers how the site''s data is backed up and how it is restored if something goes wrong.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"What must be backed up","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The database (all community content, member records, discussions)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The codebase (version-controlled in the public repository — this is the backup)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Configuration and environment settings (stored securely, separate from the code)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any uploaded media or files","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Backup frequency and retention","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Database: automated daily backups, retained for 30 days.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Configuration: backed up whenever changed, retained indefinitely.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Backups are stored in at least two geographically separate locations.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Testing backups","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Backups are only useful if they actually work. The administrator tests recovery from backup at least once every six months by:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Restoring a backup to a test environment.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Verifying that the site runs correctly from the restored data.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Documenting the test result and the time taken.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Recovery procedure","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If data loss or corruption occurs:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Identify the scope of the loss — what data, covering what time period.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Identify the most recent clean backup.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Notify the Custodian Board and volunteers of the situation before beginning recovery.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Restore to the test environment first to confirm the backup is good.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Restore to production.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Communicate publicly what happened and what data (if any) was lost.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":6,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Open source as a continuity mechanism","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The site''s codebase is published under an open source licence. In the event that the Society ceases to operate or loses access to its infrastructure, any member of the community can take the codebase and rebuild the site elsewhere. This is intentional — community knowledge should not be locked up in any single organisation''s infrastructure.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-proc-backup-and-recovery'),
  ('complaint-handling', 'Complaint Handling', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This procedure covers how formal complaints — about member or volunteer conduct — are received, investigated, and resolved by the Custodian Board.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"What this procedure covers","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This procedure applies to formal written complaints about:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Volunteer conduct that may breach the kaupapa or code of conduct","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Custodian Board member conduct","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any other matter affecting the welfare of members or the integrity of the Society","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"It does not cover content moderation (see the Content Moderation procedure) or operational disagreements between volunteers (which are resolved by volunteers themselves).","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Submitting a complaint","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any member may submit a formal complaint in writing to the Custodian Board via the Secretary. A complaint should include:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The name of the person the complaint is about","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A description of the conduct in question","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any relevant dates, messages, or evidence","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"What outcome the complainant is seeking","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Acknowledging the complaint","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Board acknowledges receipt of the complaint within five working days.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Investigation","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Board appoints one member to coordinate the investigation. That member must have no personal conflict of interest with either party.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The person the complaint is about is informed of the complaint and given a written summary of the allegations. They are given at least 10 working days to respond in writing.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Board considers the complaint and the response together. It may speak to other witnesses if necessary.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Throughout the process, both parties are treated with fairness and respect.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Determination","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Board makes its determination by consensus. Possible outcomes include:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"No action — the conduct did not breach the kaupapa or code of conduct","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Informal resolution — the Board facilitates a conversation between the parties","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Formal warning","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Temporary suspension of volunteer responsibilities","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Removal from a volunteer role","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Referral to external mediation","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":6,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Both parties are notified of the determination in writing, with brief reasons.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Confidentiality","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Complaints, investigations, and determinations are confidential to the parties and the Board. Minutes record only that a complaint was received and its outcome — not identifying details — unless both parties consent to fuller disclosure.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Appeals","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A party who believes the process was unfair may raise this with the full Board in writing within 14 days of the determination. The Board reviews the process (not the merits) and determines whether it was conducted fairly.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-proc-complaint-handling'),
  ('content-moderation', 'Content Moderation', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This procedure covers how reported or problematic content is handled on the site.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Receiving a report","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any community member may report content they believe breaches the site''s kaupapa or code of conduct using the reporting tool or by contacting a volunteer directly.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The volunteer receiving the report acknowledges it within 24 hours.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Reports are logged with: date received, content reported, reason given, and reporter''s contact (if provided).","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Initial assessment","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A volunteer with moderation responsibilities reviews the reported content and determines whether it:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Clearly breaches the code of conduct (act immediately — see below)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Possibly breaches but requires judgment (escalate to a second volunteer)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Does not breach (close the report and notify the reporter with a brief explanation)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Removing content","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If content clearly breaches the code of conduct, a moderating volunteer may remove it immediately without prior approval.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The person who posted the content is notified of the removal, the reason, and their right to respond.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The removal is logged.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Disputed removals","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If the poster disputes the removal, they may submit a written request for review within 7 days.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A second volunteer (not involved in the original decision) reviews the request.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If the second volunteer agrees with the removal, it stands. If they disagree, the content is reinstated and the matter is discussed among volunteers.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If volunteers cannot reach consensus, the matter may be referred to the Custodian Board.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Repeat or serious breaches","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If a member repeatedly breaches the code of conduct, or commits a single serious breach, the matter is referred to the Custodian Board as a formal complaint.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Custodian Board follows the complaint procedure in the bylaws.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-proc-content-moderation'),
  ('domain-and-hosting', 'Domain and Hosting Management', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This procedure covers the ongoing management of featherston.co.nz and all hosting infrastructure. Continuity of the domain is central to the Society''s purpose.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Domain registration","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The domain featherston.co.nz must be registered to the Society, not to any individual.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Renewal reminders must be set at least 60 days before expiry.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The domain must be renewed promptly. Lapsing the domain is a critical failure — domain squatters monitor for expired domains constantly.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Two volunteers must have independent access to the registrar account.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"DNS management","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All DNS changes must be documented before being applied.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Changes should be made during low-traffic periods where possible.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The current DNS configuration must be kept in the shared documentation.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Hosting and infrastructure","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Hosting accounts must be held in the Society''s name, not an individual''s.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"At least two volunteers must have administrator access to all hosting accounts.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Hosting renewal dates must be tracked in the shared infrastructure register.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The administrator reviews hosting costs and contracts annually and reports to the Custodian Board.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Credential management","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All credentials (domain registrar, hosting, DNS, server access) must be stored in the shared password manager.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"No critical credential may be held only by one person.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"When a volunteer steps back, their access is revoked and the shared credentials are rotated.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Annual review","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The administrator conducts an annual review of all infrastructure covering:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Domain registration status and renewal dates","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Hosting contracts — costs, terms, and whether they remain appropriate","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All service accounts — which are active, which are no longer needed","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"SSL certificate validity","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Access audit — confirming who has access to what, and revoking any that is no longer needed","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The review is documented and shared with volunteers and the Custodian Board.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-proc-domain-and-hosting'),
  ('financial-reporting', 'Financial Reporting', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This procedure covers how the Society''s finances are managed, reported, and published. Radical financial transparency is a core commitment.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Day-to-day financial management","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Treasurer maintains accurate records of all income and expenditure.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All income (member contributions, any grants or donations) is recorded with the date, amount, and source.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All expenditure is recorded with the date, amount, payee, and purpose.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Receipts and invoices are retained for at least seven years.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Withdrawals above NZ$500 require authorisation from the Treasurer plus at least one Custodian Board member.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Quarterly reporting","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Within 30 days of the end of each quarter, the Treasurer publishes a brief financial report covering:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Total income received during the quarter, broken down by type","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Total expenditure during the quarter, broken down by category","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Opening and closing bank balance","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any unusual items or matters requiring Voting Member attention","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The report is published publicly on the site and presented at the next Board meeting.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Annual accounts","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"At year end, the Treasurer prepares full annual financial statements including:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Income and expenditure statement for the year","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Balance sheet as at year end","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Notes explaining any significant items","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The annual statements are presented at the AGM and published publicly.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Audit and review","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Custodian Board determines each year whether the accounts require an independent review or audit, having regard to the size of the Society''s funds and any legal requirements under the Incorporated Societies Act 2022.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Contribution cap compliance","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Society accepts contributions of no more than NZ$20 per person or organisation per year. The Treasurer monitors contributions and flags any that approach or exceed this cap. Any excess is returned promptly.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-proc-financial-reporting'),
  ('it-incident-response', 'IT Incident Response', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This procedure covers how the team responds when something goes wrong with the site''s technology — outages, security incidents, data issues, or infrastructure failures.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Severity levels","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"P1 — Critical:","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Site is down or inaccessible, data breach suspected, account compromise confirmed. ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"P2 — High:","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Major feature broken, significant performance degradation, suspected but unconfirmed security issue. ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"P3 — Low:","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Minor feature broken, cosmetic issue, non-urgent infrastructure concern.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Immediate response (P1)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The person who discovers the issue alerts the administrator and at least one other volunteer immediately, using the fastest available channel.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The administrator (or most technically capable available volunteer) begins diagnosis within 30 minutes.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A brief status note is posted publicly on the site or via the community''s communication channels so people know what is happening.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If a data breach is suspected, no further diagnosis is undertaken until the administrator has isolated the affected systems.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Diagnosis and resolution","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Document what is known before making changes: what symptoms are visible, what changed recently, what the logs show.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Make one change at a time and observe the result.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Keep a running log of actions taken during the incident.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Data breach procedure","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If a breach of personal data is confirmed or strongly suspected:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Isolate affected systems immediately.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Notify the Custodian Board within 24 hours.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Assess what data was affected and how many people are involved.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If the breach is notifiable under the Privacy Act 2020, notify the Privacy Commissioner and affected individuals promptly. Take legal advice if unsure.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Publish a transparent account of what happened once the immediate incident is resolved.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Post-incident review","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"After any P1 or P2 incident:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Write a brief incident report covering: what happened, how it was discovered, what was done, and what would prevent it happening again.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Share the report with all volunteers.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Implement any preventive measures identified, with a responsible person and a due date.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Keeping systems documented","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All credentials must be stored in the shared password manager, not in any individual''s personal accounts.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Access credentials must be transferred when a volunteer steps back from a role.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The administrator maintains a current record of all services, accounts, and renewal dates.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-proc-it-incident-response'),
  ('statutory-compliance', 'Statutory Compliance', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This procedure ensures the Society meets its legal obligations as an incorporated society under the Incorporated Societies Act 2022.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Annual return","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Society must file an annual return with the Registrar of Incorporated Societies within six months of the end of each financial year. The Secretary is responsible for this.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The annual return includes:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Confirmation that the Society has held an AGM","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Current contact persons","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Current registered address","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Confirmation that the Society is still operating","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any changes to the constitution during the year","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Secretary sets a calendar reminder 8 weeks before the due date and files at least 2 weeks early.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Register of members","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Society must maintain a register of members as required by the 2022 Act. The register includes:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Full name of each member","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Date of joining","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Membership status (Voting Member or otherwise)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Date of resignation or removal (if applicable)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The register is maintained by the Secretary, kept secure, and not published publicly. Members may request to see their own entry.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Constitution changes","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any amendment to the constitution must be:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Passed by the required majority at a General Meeting (per the constitution''s amendment clause)","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Filed with the Registrar within the timeframe required by the 2022 Act","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Published to all members promptly","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Secretary is responsible for filing constitutional amendments.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Contact persons","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Society must maintain 1–3 contact persons registered with the Registrar. The Secretary ensures contact person details are current and updates the register promptly when they change.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Winding up","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If the Society resolves to wind up, it must follow the procedure in the Incorporated Societies Act 2022. Any remaining assets after debts are settled must be distributed as specified in the constitution — to another community organisation with similar purposes, not to members.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Compliance calendar","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Secretary maintains a calendar of all statutory deadlines including:","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"AGM deadline","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Annual return deadline","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Financial year end","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any other reporting obligations","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This calendar is shared with the Custodian Board and reviewed at the first quarterly meeting of each year.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-proc-statutory-compliance'),
  ('volunteer-onboarding', 'Volunteer Onboarding', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This procedure covers how new volunteers are welcomed and given the access they need to contribute effectively.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Before they start","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Confirm the person is a current Voting Member (contribution of NZ$5+ in the past 12 months).","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Ask them what they''d like to work on and what skills they''re bringing.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Assign a point of contact from the existing volunteer team — someone who will check in with them in their first few weeks.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Granting access","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Access should be granted based on what the volunteer actually needs. Do not grant more access than required.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Site content access","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" — provided to all volunteers via the site''s contributor tools.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Code repository access","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" — granted to volunteers working on the codebase.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Shared documents and task tracking","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" — granted to all volunteers.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Social media or communication channels","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" — granted to volunteers taking on communication responsibilities.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Financial systems","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" — granted only to the Treasurer and with Custodian Board approval.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All access grants must be logged with the volunteer''s name, the access level granted, and the date.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"First week","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The point of contact introduces the new volunteer to the rest of the team.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The new volunteer is given a brief tour of active work in progress and any relevant context.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The volunteer starts with something small and well-defined — a task they can complete and see the result of quickly.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Ongoing","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"There is no formal probation period. Volunteers are trusted from the start.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The point of contact checks in informally after two weeks and again after a month.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If a volunteer is struggling or unsure, the expectation is that they ask — and that the team responds helpfully.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If a volunteer steps back","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The volunteer notifies the team and agrees a reasonable handover timeline.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All access is revoked promptly after handover is complete.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Access revocations are logged.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"number","start":1,"tag":"ol","type":"list","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-proc-volunteer-onboarding'),
  ('custodian-bylaws', 'Custodian Board Bylaws', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"These bylaws govern the formal operation of the Custodian Board. They flow directly from the constitution and are binding on all Board members. They may only be changed through a formal amendment process consistent with the constitution.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1. Meetings","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1.1 Frequency","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Custodian Board meets at least once per calendar quarter. Additional meetings may be called as needed.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1.2 Calling a meeting","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any Board member may call a meeting by giving at least five working days'' written notice to all other members, stating the business to be transacted.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1.3 Quorum","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All five members of the Custodian Board must be present for a meeting to proceed. If a member cannot attend, the meeting must be rescheduled. There are no proxy votes.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1.4 Facilitator","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"At the start of each meeting, members appoint a facilitator by consensus. The role rotates among members. The facilitator has no casting vote and no authority beyond facilitating discussion.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1.5 Remote attendance","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Members may attend by video call. Remote attendance counts toward quorum provided the member can hear and participate in all discussion.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"2. Decision-making","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"2.1 Consensus required","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All Board decisions require the consensus of all five members. A decision is reached when every member present agrees. There is no majority voting and no casting vote.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"2.2 Deadlock","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If consensus cannot be reached, the matter is adjourned to a subsequent meeting. If consensus still cannot be reached at that subsequent meeting, the matter is referred to a Special General Meeting of Voting Members.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"2.3 Out-of-session decisions","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"In urgent circumstances, decisions may be made by written consensus (email or equivalent) provided all five members respond and all agree. Any out-of-session decision must be recorded in the minutes of the next meeting.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"3. Minutes and records","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"3.1 Minutes","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A written record must be kept of every meeting, including: who attended, what was discussed, what decisions were made, and any action items with responsible persons and due dates.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"3.2 Publication","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Minutes must be published to all Voting Members within 14 days of the meeting.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"3.3 Retention","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All minutes and Board correspondence must be retained for at least seven years and handed over to the incoming Board at the end of each term.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"4. Financial authorisation","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"4.1 Routine expenditure","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Treasurer may authorise expenditure up to NZ$500 without Board approval.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"4.2 Significant expenditure","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any single expenditure above NZ$500 requires written authorisation from the Treasurer plus at least one Custodian Board member.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"4.3 Financial reporting","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Treasurer must provide a written financial report at every quarterly Board meeting. Accounts must be published publicly within 30 days of each quarter end.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"5. Conflicts of interest","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"5.1 Declaration","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any Board member with a financial or personal interest in a matter before the Board must declare that interest at the start of discussion.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"5.2 Recusal","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A member who has declared a conflict must not participate in the discussion or decision on that matter. Their absence does not affect quorum for that item only.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"5.3 Recording","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"All declared conflicts of interest must be recorded in the minutes.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"6. Vacancies","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"6.1 Mid-term vacancy","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If a Board position becomes vacant between AGMs, the remaining members shall invite a replacement from eligible Voting Members by consensus, to serve until the next AGM.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"6.2 Reduced Board","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If a vacancy reduces the Board to fewer than three members, a Special General Meeting must be called within 30 days to conduct a supplementary sortition.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"7. Complaints","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"7.1 Receiving complaints","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Board must acknowledge any written complaint from a member or volunteer within five working days.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"7.2 Process","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Board must give any person the subject of a complaint a fair opportunity to respond before making a determination.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"7.3 Confidentiality","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Complaints and proceedings are confidential to the parties and the Board, unless the Board determines that publication is in the interests of the Society.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-pol-custodian-bylaws'),
  ('custodian-guidelines', 'Custodian Board Guidelines', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"These guidelines are practical guidance for Custodian Board members. Unlike the bylaws, they are not formally binding — they reflect what has worked well and should be updated by the Board as experience grows.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Before your term begins","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Read the constitution, the bylaws, and the previous Board''s minutes in full before your first meeting.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Make sure you have access to all shared accounts, documents, and communication channels. If handover is incomplete, raise it immediately with the outgoing Board.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Introduce yourself to the current volunteers. You are there to support them, not to manage them.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Running good meetings","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Circulate an agenda at least two days before each meeting. Members should know what they are being asked to decide.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Start by checking whether any member has a conflict of interest on any agenda item.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The facilitator''s job is to make sure every member speaks and that the discussion moves. It is not to direct the outcome.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If you are going in circles, name it. \"We''ve been on this for 20 minutes and we''re not converging — should we table it?\"","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"End every meeting with clear action items: what, who, by when.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Publish minutes within 14 days. Write them so that someone who wasn''t there understands what was decided and why.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":6,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Between meetings","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Stay in contact. If something comes up that might need Board attention, raise it with other members early rather than waiting for the next meeting.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Do not make unilateral statements on behalf of the Board. If a volunteer or member asks for a Board position on something, the answer is that it will be discussed at the next meeting.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If you receive a complaint or concern informally, encourage the person to submit it in writing so it can be properly considered.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Working with volunteers","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Volunteers make all positive decisions. Your role is oversight, not management. Resist the urge to offer opinions on what the site should look like or what features should be built.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If you have ideas about the site, contribute as a volunteer, not as a Board member.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Be visible and approachable. Volunteers should feel comfortable raising concerns with you informally before they escalate.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Handling complaints","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Take complaints seriously even when they seem minor. Early intervention prevents escalation.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Be genuinely fair. Before forming a view, hear from everyone involved.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Document everything. Even informal conversations about concerns should be noted.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"When in doubt, seek outside perspective. The Board can bring in a mediator.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"End of term","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Write a brief handover note for the incoming Board covering: anything unresolved, anything the new Board should know about, and anything you wish you''d known at the start.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Transfer all access and credentials on or before the AGM.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Stay available for a short period after your term to answer questions from the incoming Board.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-pol-custodian-guidelines'),
  ('volunteer-bylaws', 'Volunteer Bylaws', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"These bylaws set out the formal expectations for volunteers. They are intentionally minimal — volunteers run this organisation and should not be burdened with bureaucracy. The goal is clarity, not control.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1. Becoming a volunteer","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1.1 Eligibility","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Any Voting Member may volunteer. Voting Membership requires a contribution of NZ$5 or more in the past 12 months and acceptance of the Society''s kaupapa and code of conduct.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1.2 No formal application","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"There is no application process. A person becomes a volunteer by expressing availability, agreeing to work in accordance with the kaupapa, and beginning to contribute.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1.3 Roles","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Volunteer roles are defined and published by volunteers themselves. Any volunteer may propose a new role or take on existing responsibilities. There is no approval required from the Custodian Board for positive operational decisions.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"2. Decision-making","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"2.1 Collective authority","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Volunteers collectively hold all positive decision-making authority over the Society''s operations — what to build, what to publish, how to organise. No Board approval is required.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"2.2 Resolving disagreements","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Where volunteers disagree on an operational matter, they resolve it among themselves by discussion and consensus. The Custodian Board does not adjudicate operational disagreements unless a formal complaint is lodged.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"2.3 No hierarchy","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"There is no management hierarchy among volunteers. Influence comes from contribution, expertise, and the trust of other volunteers — not from title or seniority.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"3. Conduct","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"3.1 Kaupapa","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Volunteers are expected to act in accordance with the Society''s kaupapa at all times — in their work, their communications, and their interactions with other members and the community.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"3.2 Code of conduct","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Volunteers must comply with the Society''s code of conduct. Breaches may result in a formal complaint to the Custodian Board.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"3.3 Conflicts of interest","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Volunteers must not use their position to benefit themselves or any organisation they are connected to. Where a potential conflict arises, it should be declared openly to other volunteers.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"4. Stepping back and removal","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"4.1 Stepping back","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A volunteer may step back from their role at any time by notifying other volunteers and completing any reasonable handover of work in progress.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"4.2 Removal","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h3","type":"heading","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Custodian Board may remove a volunteer who has materially breached the kaupapa or code of conduct, after giving them a fair opportunity to respond.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-pol-volunteer-bylaws'),
  ('volunteer-guidelines', 'Volunteer Guidelines', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"These are practical guidelines for volunteers. They are not rules — they reflect what makes contributing here work well. Update them when you find something better.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Getting started","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Read the kaupapa and the volunteer bylaws before you begin.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Have a look at what''s already been built and what''s in progress. The best way to start is to pick something small and useful and do it.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Introduce yourself to existing volunteers. There''s no formal onboarding, but people are friendly.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Don''t wait for permission. If something needs doing and you''re able to do it, do it.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"How work gets coordinated","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Work is coordinated openly. Use the shared channels and tools so everyone can see what''s in progress.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If you''re starting something significant, mention it so others know and can weigh in or avoid duplicating effort.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"There are no deadlines unless you set them. Take on what you can sustain, not what sounds impressive.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If you''re stuck, ask. If you''re blocked by someone else, say so clearly and early.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Making decisions","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Small decisions: just make them. You don''t need sign-off.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Bigger decisions that affect others: talk to the other volunteers involved before acting. A brief message is usually enough.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If you''re genuinely unsure whether something is within your scope, err on the side of discussing it first.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Disagreements: talk directly to the person first. Most things resolve quickly that way.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Communication","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Be direct and kind. Say what you think, and assume good intent from others.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Written communication loses tone easily. If a message could be read as critical, add some warmth.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Don''t let things fester. If something bothers you, name it early and informally before it becomes a bigger deal.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Decisions made in conversations should be written down somewhere others can see.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Raising concerns","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If something feels wrong — a decision, a behaviour, a direction — raise it. You don''t have to be certain; you just have to name it.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Talk to another volunteer first. Most concerns can be resolved without formal process.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If informal resolution doesn''t work, you can submit a written complaint to the Custodian Board. They will take it seriously.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"You will not be penalised for raising concerns in good faith.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Handing over work","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"When you step back from a piece of work, write a short note about where things stand, what''s unfinished, and anything the next person needs to know.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Make sure access (accounts, files, credentials) is transferred and not left with only you.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A clean handover is one of the most valuable things you can do for the organisation.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Looking after each other","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"tag":"h2","type":"heading","version":1},{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Notice when someone is burning out. Say something.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Celebrate things that go well. It matters.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This should be enjoyable. If it stops being enjoyable, that''s worth talking about.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1}],"direction":"ltr","format":"","indent":0,"listType":"bullet","start":1,"tag":"ul","type":"list","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'system', 'System', true, 1, 'gov-pol-volunteer-guidelines')
